__global__ void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int row_base = (blockIdx.y * blockDim.y + threadIdx.y) * 2;
    int col_base = (blockIdx.x * blockDim.x + threadIdx.x) * 4;
    float acc00 = 0.0f;
    float acc01 = 0.0f;
    float acc02 = 0.0f;
    float acc03 = 0.0f;
    float acc10 = 0.0f;
    float acc11 = 0.0f;
    float acc12 = 0.0f;
    float acc13 = 0.0f;
    if (row_base + 1 < M && col_base + 3 < N) {
        for (int k = 0; k < K; k++) {
            float a0 = A[row_base * K + k];
            float a1 = A[(row_base + 1) * K + k];
            float4 b4 = *reinterpret_cast<float4*>(&B[k * N + col_base]);
            acc00 += a0 * b4.x;
            acc01 += a0 * b4.y;
            acc02 += a0 * b4.z;
            acc03 += a0 * b4.w;
            acc10 += a1 * b4.x;
            acc11 += a1 * b4.y;
            acc12 += a1 * b4.z;
            acc13 += a1 * b4.w;
        }
    }
    if (row_base + 1 < M && col_base + 3 < N) {
        C[(row_base + 0) * N + (col_base + 0)] = acc00;
        C[(row_base + 0) * N + (col_base + 1)] = acc01;
        C[(row_base + 0) * N + (col_base + 2)] = acc02;
        C[(row_base + 0) * N + (col_base + 3)] = acc03;
        C[(row_base + 1) * N + (col_base + 0)] = acc10;
        C[(row_base + 1) * N + (col_base + 1)] = acc11;
        C[(row_base + 1) * N + (col_base + 2)] = acc12;
        C[(row_base + 1) * N + (col_base + 3)] = acc13;
    }
}
